<?php require_once __DIR__.'/includes/functions.php';$token=$_GET['token']??'';$s=db()->prepare("SELECT * FROM password_resets WHERE token=? AND used_at IS NULL AND expires_at>NOW()");$s->execute([$token]);$r=$s->fetch();if(!$r){flash('error','Invalid or expired link');redirect('/forgot-password.php');}if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();db()->prepare("UPDATE users SET password_hash=? WHERE id=?")->execute([password_hash($_POST['password'],PASSWORD_DEFAULT),$r['user_id']]);db()->prepare("UPDATE password_resets SET used_at=NOW() WHERE id=?")->execute([$r['id']]);flash('success','Password updated');redirect('/login.php');}include __DIR__.'/includes/header.php';?><section class="section"><h1>Reset Password</h1><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>New Password<input name="password" type="password" minlength="8"></label><button>Update</button></form></section><?php include __DIR__.'/includes/footer.php'; ?>